import{_ as o,o as e,c as d,ag as a}from"./chunks/framework.wqPkq5Rj.js";const u=JSON.parse('{"title":"操作技巧与快捷键","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tips.md","filePath":"guide/tips.md","lastUpdated":1777169627000}'),r={name:"guide/tips.md"};function p(c,t,n,s,h,i){return e(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="操作技巧与快捷键" tabindex="-1">操作技巧与快捷键 <a class="header-anchor" href="#操作技巧与快捷键" aria-label="Permalink to &quot;操作技巧与快捷键&quot;">​</a></h1><h2 id="markdown-编辑技巧" tabindex="-1">Markdown 编辑技巧 <a class="header-anchor" href="#markdown-编辑技巧" aria-label="Permalink to &quot;Markdown 编辑技巧&quot;">​</a></h2><p><strong>快速插入格式</strong></p><table tabindex="0"><thead><tr><th>输入</th><th>效果</th></tr></thead><tbody><tr><td><code>#</code> + 空格</td><td>一级标题</td></tr><tr><td><code>##</code> + 空格</td><td>二级标题</td></tr><tr><td><code>-</code> + 空格</td><td>无序列表</td></tr><tr><td><code>1.</code> + 空格</td><td>有序列表</td></tr><tr><td><code>```</code></td><td>代码块</td></tr><tr><td><code>---</code></td><td>分割线</td></tr></tbody></table><p><strong>划词引用</strong></p><p>选中一段文字点击工具栏中「 &quot; 」，可以将文字添加至 chat 输入框中。</p><p><strong>划词评论</strong></p><p>选中一段文字，点击「💬」。</p><p>momo 可以读取文档里的所有评论，并在你的授权下回应它们。</p><p><strong>在编辑模式下划词编辑</strong></p><p>选中文字会展示编辑工具栏，可以编辑文本类型（标题、正文、加粗、斜体等）。</p><p><strong>「/」添加内容</strong></p><p>选中文字后，工具栏中点击「/」可在选中位置插入新的内容块，快速在段落间添加文字、列表、代码块等。</p><hr><h2 id="几个省时间的用法" tabindex="-1">几个省时间的用法 <a class="header-anchor" href="#几个省时间的用法" aria-label="Permalink to &quot;几个省时间的用法&quot;">​</a></h2><p><strong>让 momo 在当前文档里直接操作</strong></p><p>你打开一篇文档，对 momo 说：「在这篇文档的第二节后面，插入一个关于竞品对比的表格，数据用 Workspace 里已有的竞品分析内容。」</p><p>它会直接修改这篇文档，不需要你复制粘贴。</p><p><strong>用 @ 引用文档</strong></p><p>在 momo 的输入框里输入 <code>@</code>，可以搜索并引用 Workspace 里的文件。</p><blockquote><p>&quot;@竞品分析 里关于定价部分的内容，帮我整理成一个对比表。&quot;</p></blockquote><p>也可以直接在左侧<strong>目录树</strong>操作：鼠标悬停在任意文件上，点击文件名旁出现的 <code>@</code> 图标，该文件会自动插入当前 chat 输入框，不用手动输入文件名。</p><p><strong>批量处理文件</strong></p><blockquote><p>&quot;把「会议纪要」文件夹里所有 2024 年以前的文件，移动到 <code>_archived/</code> 文件夹。&quot;</p></blockquote><p>momo 可以一次处理多个文件，不需要你一个个操作。</p><p><strong>设定输出位置</strong></p><blockquote><p>&quot;帮我写一份本周工作总结，直接新建一个文件，放到「周报」文件夹，文件名用今天的日期。&quot;</p></blockquote><p>你不需要先建文件再让它写，直接说在哪里创建什么内容就好。</p><hr><h2 id="编辑与保存" tabindex="-1">编辑与保存 <a class="header-anchor" href="#编辑与保存" aria-label="Permalink to &quot;编辑与保存&quot;">​</a></h2><p>点击文档右上角的「编辑」按钮进入编辑模式，编辑完成后点击右上角的「✓」保存文档。</p><p>文档有版本历史，可以通过右上角的「历史版本」查看和恢复任意时间点的内容。</p><h2 id="常用快捷键" tabindex="-1">常用快捷键 <a class="header-anchor" href="#常用快捷键" aria-label="Permalink to &quot;常用快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>Mac</th><th>Windows</th></tr></thead><tbody><tr><td>搜索 Workspace</td><td><code>Cmd + K</code></td><td><code>Ctrl + K</code></td></tr></tbody></table>',34)])])}const m=o(r,[["render",p]]);export{u as __pageData,m as default};
